import { SandboxAgentScreen } from "@/components/sandbox-agent/sandbox-agent-screen";

export default function SandboxAgentPage() {
  return <SandboxAgentScreen />;
}

import { handleSandboxAgentRequest } from "@/lib/sandbox-agent/server/request";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleSandboxAgentRequest(request);
}

const PREVIEW_ERROR_CODE_RE = /^[A-Z0-9_]+$/;

function readPreviewErrorCode(response: Response, body: string) {
  const headerCode = response.headers.get("x-vercel-error");

  if (headerCode) {
    return headerCode;
  }

  const bodyCode = body
    .split("\n")
    .map((line) => line.trim())
    .find((line) => PREVIEW_ERROR_CODE_RE.test(line));

  return bodyCode ?? null;
}

function trimBody(body: string) {
  const trimmed = body.trim();

  if (!trimmed) {
    return null;
  }

  return trimmed.slice(0, 280);
}

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const url = searchParams.get("url");

  if (!url) {
    return Response.json(
      {
        errorCode: "MISSING_URL",
        message: "A preview URL is required.",
        ok: false,
        status: null,
        statusText: null,
      },
      { status: 400 }
    );
  }

  let parsedUrl: URL;

  try {
    parsedUrl = new URL(url);
  } catch {
    return Response.json(
      {
        errorCode: "INVALID_URL",
        message: "The preview URL is not a valid absolute URL.",
        ok: false,
        status: null,
        statusText: null,
      },
      { status: 400 }
    );
  }

  if (!["http:", "https:"].includes(parsedUrl.protocol)) {
    return Response.json(
      {
        errorCode: "INVALID_PROTOCOL",
        message: "The preview URL must use http or https.",
        ok: false,
        status: null,
        statusText: null,
      },
      { status: 400 }
    );
  }

  try {
    const response = await fetch(parsedUrl, {
      cache: "no-store",
      redirect: "follow",
    });
    const body = trimBody(await response.text());

    return Response.json({
      errorCode: response.ok
        ? null
        : readPreviewErrorCode(response, body ?? ""),
      message: response.ok ? null : body,
      ok: response.ok,
      status: response.status,
      statusText: response.statusText || null,
    });
  } catch (error) {
    return Response.json({
      errorCode: "FETCH_FAILED",
      message:
        error instanceof Error ? error.message : "Failed to check preview URL.",
      ok: false,
      status: null,
      statusText: null,
    });
  }
}

import { posix as posixPath } from "node:path";

function normalizeEntryPath(entryPath: string) {
  const normalizedPath = posixPath
    .normalize(entryPath.startsWith("/") ? entryPath : `/${entryPath}`)
    .replace(/^(\.\.(\/|\\|$))+/, "");

  return normalizedPath === "/" ? "/index.html" : normalizedPath;
}

function buildPathPreviewUrl({
  directory,
  entryPath,
  request,
  sessionId,
}: {
  directory: string;
  entryPath: string;
  request: Request;
  sessionId: string;
}) {
  const normalizedDirectory =
    directory === "." ? "" : directory.replace(/^\/+/, "");
  const previewPath = posixPath.join(
    normalizedDirectory,
    normalizeEntryPath(entryPath).slice(1)
  );
  const url = new URL(request.url);
  url.pathname = [
    "/api/demos/sandbox-agent/local-preview",
    encodeURIComponent(sessionId),
    ...previewPath.split("/").filter(Boolean).map(encodeURIComponent),
  ].join("/");
  url.search = "";

  return url;
}

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const sessionId = searchParams.get("sessionId");
  const directory = searchParams.get("directory") ?? ".";
  const entryPath = searchParams.get("path") ?? "/index.html";

  if (!sessionId) {
    return new Response("Missing sessionId.", { status: 400 });
  }

  return Response.redirect(
    buildPathPreviewUrl({
      directory,
      entryPath,
      request,
      sessionId,
    }),
    307
  );
}

import { posix as posixPath } from "node:path";

import { getSandboxAgentEnv } from "@/lib/sandbox-agent/server/env";
import { getSharedSandboxAgentSessionRegistry } from "@/lib/sandbox-agent/server/session";

const contentTypes = new Map([
  [".css", "text/css; charset=utf-8"],
  [".html", "text/html; charset=utf-8"],
  [".js", "text/javascript; charset=utf-8"],
  [".json", "application/json; charset=utf-8"],
  [".mjs", "text/javascript; charset=utf-8"],
  [".svg", "image/svg+xml; charset=utf-8"],
  [".txt", "text/plain; charset=utf-8"],
]);

function normalizePreviewPath(pathSegments: string[]) {
  const normalizedPath = posixPath
    .normalize(`/${pathSegments.join("/")}`)
    .replace(/^(\.\.(\/|\\|$))+/, "");

  return normalizedPath === "/" ? "/index.html" : normalizedPath;
}

function getContentType(targetPath: string) {
  return (
    contentTypes.get(posixPath.extname(targetPath)) ??
    "text/plain; charset=utf-8"
  );
}

export async function GET(
  request: Request,
  {
    params,
  }: {
    params: Promise<{
      path?: string[];
      sessionId: string;
    }>;
  }
) {
  const { path = [], sessionId } = await params;
  const registry = await getSharedSandboxAgentSessionRegistry(
    getSandboxAgentEnv(),
    {
      localPreviewBaseUrl: new URL(request.url).origin,
    }
  );
  const session = registry.getSession(sessionId);
  const targetPath = normalizePreviewPath(path).slice(1);

  try {
    return new Response(await session.readFile(targetPath), {
      headers: {
        "content-type": getContentType(targetPath),
      },
    });
  } catch (error) {
    return new Response(
      error instanceof Error ? error.message : "Preview file not found.",
      {
        headers: {
          "content-type": "text/plain; charset=utf-8",
        },
        status: 404,
      }
    );
  }
}

"use client";

import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";

import { SandboxConversationPane } from "./sandbox-conversation-pane";
import { SandboxPreviewPane } from "./sandbox-preview-pane";
import { SandboxRuntimeSidebar } from "./sandbox-runtime-sidebar";
import { useSandboxAgentWorkspaceViewModel } from "./use-sandbox-agent-workspace-view-model";

export interface SandboxAgentWorkspaceProps {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  previewPort: number;
  sandboxProvider: string;
  setupMessage: string | null;
}

export function SandboxAgentWorkspace({
  chatModel,
  isChatAvailable,
  nodeVersion,
  previewPort,
  sandboxProvider,
  setupMessage,
}: SandboxAgentWorkspaceProps) {
  const workspace = useSandboxAgentWorkspaceViewModel();

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_22rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {workspace.error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {workspace.error.message}
          </div>
        ) : null}

        {workspace.isTabsMounted ? (
          <Tabs
            className="flex min-h-0 flex-1 flex-col gap-0"
            onValueChange={(value) =>
              workspace.actions.onTabChange(value as "conversation" | "preview")
            }
            value={workspace.activeTab}
          >
            <div className="border-foreground/10 border-b px-4 py-2">
              <TabsList className="grid w-fit grid-cols-2">
                <TabsTrigger value="conversation">Conversation</TabsTrigger>
                <TabsTrigger value="preview">Preview</TabsTrigger>
              </TabsList>
            </div>

            <SandboxConversationPane
              chatModel={chatModel}
              hasMessages={workspace.hasMessages}
              isBusy={workspace.isBusy}
              isChatAvailable={isChatAvailable}
              messages={workspace.messages}
              onOpenPreview={workspace.actions.onOpenPreview}
              onRegenerate={workspace.actions.onRegenerate}
              onSendMessage={workspace.actions.onSendMessage}
              onStop={workspace.actions.onStop}
              samplePrompts={workspace.samplePrompts}
              sandboxProvider={sandboxProvider}
              status={workspace.status}
            />

            <SandboxPreviewPane
              latestPreview={workspace.latestPreview}
              previewState={workspace.previewState}
            />
          </Tabs>
        ) : (
          <div className="flex min-h-0 flex-1 flex-col">
            <div className="border-foreground/10 border-b px-4 py-2">
              <div className="h-8 w-48 bg-muted" />
            </div>
            <div className="min-h-0 flex-1" />
          </div>
        )}
      </section>

      <SandboxRuntimeSidebar
        nodeVersion={nodeVersion}
        previewPort={previewPort}
        sandboxProvider={sandboxProvider}
      />
    </div>
  );
}

"use client";

import type { useChat } from "@ai-sdk/react";
import { StopIcon, WrenchIcon } from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { TabsContent } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";
import type { UIMessage } from "ai";

import { SandboxAgentAssistantTrace } from "./sandbox-agent-assistant-trace";
import { getTextContent } from "./sandbox-agent-model";

interface SandboxConversationPaneProps {
  chatModel: string;
  hasMessages: boolean;
  isBusy: boolean;
  isChatAvailable: boolean;
  messages: UIMessage[];
  onOpenPreview: () => void;
  onRegenerate: () => void;
  onSendMessage: (text: string) => void;
  onStop: () => void;
  samplePrompts: readonly string[];
  sandboxProvider: string;
  status: ReturnType<typeof useChat>["status"];
}

export function SandboxConversationPane({
  chatModel,
  hasMessages,
  isBusy,
  isChatAvailable,
  messages,
  onOpenPreview,
  onRegenerate,
  onSendMessage,
  onStop,
  samplePrompts,
  sandboxProvider,
  status,
}: SandboxConversationPaneProps) {
  return (
    <TabsContent className="mt-0 min-h-0 flex-1" value="conversation">
      <div className="flex h-full min-h-0 flex-col">
        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-4xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              messages.map((message, index) => (
                <Message from={message.role} key={message.id}>
                  <MessageContent
                    className={cn(
                      "space-y-4",
                      message.role === "assistant" ? "max-w-4xl" : "max-w-2xl"
                    )}
                  >
                    {message.role === "assistant" ? (
                      <SandboxAgentAssistantTrace
                        isLastMessage={index === messages.length - 1}
                        isStreaming={isBusy}
                        message={message}
                        onOpenPreview={onOpenPreview}
                      />
                    ) : (
                      <MessageResponse>
                        {getTextContent(message)}
                      </MessageResponse>
                    )}
                  </MessageContent>
                </Message>
              ))
            ) : (
              <ConversationEmptyState
                description="Ask the agent to scaffold a static frontend prototype, edit files in the sandbox workspace, and expose a live preview."
                icon={<WrenchIcon className="size-5" />}
                title="Prototype workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-4xl">
            <PromptInput onSubmit={({ text }) => onSendMessage(text)}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Describe a frontend prototype you want to build in the sandbox."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">ToolLoopAgent</Badge>
                  <Badge variant="outline">{sandboxProvider}</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={onStop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={onRegenerate}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {samplePrompts.map((prompt) => (
                  <Button
                    key={prompt}
                    onClick={() => onSendMessage(prompt)}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <WrenchIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </TabsContent>
  );
}

"use client";

import {
  ArrowClockwiseIcon,
  ArrowLeftIcon,
  ArrowRightIcon,
  ArrowSquareOutIcon,
  ArrowsInIcon,
  ArrowsOutIcon,
  CopySimpleIcon,
} from "@phosphor-icons/react";
import {
  WebPreview,
  WebPreviewBody,
  WebPreviewConsole,
  WebPreviewNavigation,
  WebPreviewNavigationButton,
  WebPreviewUrl,
} from "@/components/ai-elements/web-preview";
import { TabsContent } from "@/components/ui/tabs";

import {
  formatPreviewStatusSummary,
  parsePreviewStatus,
} from "./preview-state";
import {
  type SandboxPreviewState,
  usePreviewHealth,
} from "./use-sandbox-preview-state";

interface LatestPreview {
  directory: string | null;
  entryPath: string | null;
  port: number | null;
  url: string;
}

interface SandboxPreviewPaneProps {
  latestPreview: LatestPreview | null;
  previewState: SandboxPreviewState;
}

export function SandboxPreviewPane({
  latestPreview,
  previewState,
}: SandboxPreviewPaneProps) {
  const previewHealth = usePreviewHealth(
    previewState.activePreviewUrl,
    previewState.previewReloadKey,
    previewState.appendPreviewLog
  );

  if (!latestPreview?.url) {
    return (
      <TabsContent className="mt-0 min-h-0 flex-1" value="preview">
        <div className="flex size-full items-center justify-center p-6 text-center">
          <div className="max-w-md space-y-2">
            <p className="font-medium text-foreground text-sm">
              Preview is not running yet
            </p>
            <p className="text-muted-foreground text-sm">
              A live preview will appear here after the agent starts a sandbox
              preview for the generated prototype.
            </p>
          </div>
        </div>
      </TabsContent>
    );
  }

  return (
    <TabsContent className="mt-0 min-h-0 flex-1" value="preview">
      <div className="size-full" ref={previewState.previewContainerRef}>
        <WebPreview
          className="size-full rounded-none border-0 bg-transparent"
          defaultUrl="/"
          key={`${previewState.activePreviewUrl}:${previewState.previewReloadKey}`}
          onUrlChange={previewState.handlePreviewUrlChange}
          style={{ height: "100%" }}
        >
          <WebPreviewNavigation>
            <WebPreviewNavigationButton
              disabled={!previewState.canGoBack}
              onClick={previewState.handleGoBack}
              tooltip="Go back"
            >
              <ArrowLeftIcon className="size-4" />
            </WebPreviewNavigationButton>
            <WebPreviewNavigationButton
              disabled={!previewState.canGoForward}
              onClick={previewState.handleGoForward}
              tooltip="Go forward"
            >
              <ArrowRightIcon className="size-4" />
            </WebPreviewNavigationButton>
            <WebPreviewNavigationButton
              onClick={previewState.handleReload}
              tooltip="Reload"
            >
              <ArrowClockwiseIcon className="size-4" />
            </WebPreviewNavigationButton>
            <WebPreviewUrl
              data-preview-url-input="true"
              value={previewState.activePreviewUrl}
            />
            <WebPreviewNavigationButton
              onClick={previewState.handleCopy}
              tooltip="Copy preview URL"
            >
              <CopySimpleIcon className="size-4" />
            </WebPreviewNavigationButton>
            <WebPreviewNavigationButton
              onClick={previewState.handleOpenInNewTab}
              tooltip="Open in new tab"
            >
              <ArrowSquareOutIcon className="size-4" />
            </WebPreviewNavigationButton>
            <WebPreviewNavigationButton
              onClick={previewState.handleToggleFullscreen}
              tooltip={
                previewState.isPreviewFullscreen ? "Restore" : "Maximize"
              }
            >
              {previewState.isPreviewFullscreen ? (
                <ArrowsInIcon className="size-4" />
              ) : (
                <ArrowsOutIcon className="size-4" />
              )}
            </WebPreviewNavigationButton>
          </WebPreviewNavigation>

          {previewHealth.state === "error" ? (
            <div className="flex min-h-0 flex-1 items-center justify-center border-t px-6 py-10 text-center">
              <div className="max-w-xl space-y-2">
                <p className="font-medium text-foreground text-sm">
                  Preview is unavailable
                </p>
                <p className="text-muted-foreground text-sm">
                  {formatPreviewStatusSummary(
                    previewHealth.details ??
                      parsePreviewStatus({
                        errorCode: "UNKNOWN_PREVIEW_ERROR",
                        message: "The preview URL could not be verified.",
                        ok: false,
                        status: null,
                        statusText: null,
                      })
                  )}
                </p>
              </div>
            </div>
          ) : (
            <WebPreviewBody
              className="min-h-0 flex-1"
              src={previewState.activePreviewUrl}
            />
          )}

          <WebPreviewConsole logs={previewState.previewLogs} />
        </WebPreview>
      </div>
    </TabsContent>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";

import { configuredTools } from "./sandbox-agent-model";

interface SandboxRuntimeSidebarProps {
  nodeVersion: string;
  previewPort: number;
  sandboxProvider: string;
}

export function SandboxRuntimeSidebar({
  nodeVersion,
  previewPort,
  sandboxProvider,
}: SandboxRuntimeSidebarProps) {
  return (
    <aside className="border border-foreground/10 bg-background p-4">
      <div className="space-y-5">
        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Runtime
          </p>
          <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
          <p className="mt-1 text-muted-foreground text-sm">
            {sandboxProvider}
          </p>
        </div>

        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Configured tools
          </p>
          {configuredTools.map((tool) => (
            <div
              className="space-y-1 border border-foreground/10 p-3"
              key={tool.name}
            >
              <p className="font-medium text-sm">{tool.name}</p>
              <p className="text-muted-foreground text-sm/relaxed">
                {tool.description}
              </p>
            </div>
          ))}
        </div>

        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Preview contract
          </p>
          <div className="mt-2 flex flex-wrap gap-2">
            <Badge variant="secondary">port {previewPort}</Badge>
            <Badge variant="secondary">HTML / CSS / JS</Badge>
            <Badge variant="secondary">live iframe</Badge>
          </div>
        </div>

        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Source core
          </p>
          <p className="mt-1 text-sm">
            The model writes code in a persistent sandbox workspace, uses bash
            and direct file tools for iteration, then calls{" "}
            <code>startPreview</code> to publish the generated prototype.
          </p>
        </div>
      </div>
    </aside>
  );
}

"use client";

import { GlobeHemisphereWestIcon } from "@phosphor-icons/react";
import { MessageResponse } from "@/components/ai-elements/message";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
} from "@/components/ai-elements/tool";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { UIMessage } from "ai";
import { getPreviewOutput, sanitizePreviewText } from "./preview-state";
import {
  getReasoningText,
  getTextContent,
  getToolParts,
  getWrittenFiles,
} from "./sandbox-agent-model";

interface SandboxAgentAssistantTraceProps {
  isLastMessage: boolean;
  isStreaming: boolean;
  message: UIMessage;
  onOpenPreview: () => void;
}

export function SandboxAgentAssistantTrace({
  isLastMessage,
  isStreaming,
  message,
  onOpenPreview,
}: SandboxAgentAssistantTraceProps) {
  const reasoningText = getReasoningText(message);
  const toolParts = getToolParts(message);
  const preview = getPreviewOutput(toolParts);
  const text = sanitizePreviewText(
    getTextContent(message),
    preview?.url ?? null
  );
  const writtenFiles = getWrittenFiles(toolParts);
  const hasReasoning = reasoningText.length > 0;
  const hasText = text.length > 0;
  const lastPart = message.parts.at(-1);
  const isReasoningStreaming =
    isLastMessage && isStreaming && lastPart?.type === "reasoning";
  const showBodyThinking =
    isLastMessage && isStreaming && !hasReasoning && !hasText;
  let bodyContent: React.ReactNode = null;

  if (hasText) {
    bodyContent = <MessageResponse>{text}</MessageResponse>;
  } else if (showBodyThinking) {
    bodyContent = <Shimmer className="text-sm">Thinking...</Shimmer>;
  }

  return (
    <>
      {hasReasoning ? (
        <Reasoning className="w-full" isStreaming={isReasoningStreaming}>
          <ReasoningTrigger />
          <ReasoningContent>{reasoningText}</ReasoningContent>
        </Reasoning>
      ) : null}

      {writtenFiles.length > 0 ? (
        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Generated files
          </p>
          <div className="flex flex-wrap gap-2">
            {writtenFiles.map((filePath) => (
              <Badge key={filePath} variant="secondary">
                {filePath}
              </Badge>
            ))}
          </div>
        </div>
      ) : null}

      {toolParts.map((part) => (
        <Tool key={part.toolCallId}>
          {part.type === "dynamic-tool" ? (
            <ToolHeader
              state={part.state}
              toolName={part.toolName}
              type={part.type}
            />
          ) : (
            <ToolHeader state={part.state} type={part.type} />
          )}
          <ToolContent>
            {part.input ? <ToolInput input={part.input} /> : null}
            <ToolOutput errorText={part.errorText} output={part.output} />
          </ToolContent>
        </Tool>
      ))}

      {preview?.url ? (
        <div className="space-y-3">
          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{preview.directory ?? "."}</Badge>
            <Badge variant="outline">port {preview.port ?? 3000}</Badge>
            {preview.entryPath ? (
              <Badge variant="secondary">{preview.entryPath}</Badge>
            ) : null}
          </div>

          <Button
            className="w-fit"
            onClick={onOpenPreview}
            type="button"
            variant="outline"
          >
            <GlobeHemisphereWestIcon className="size-4" />
            Open preview
          </Button>
        </div>
      ) : null}

      {bodyContent}
    </>
  );
}

"use client";

import type { ToolPart } from "@/components/ai-elements/tool";
