export function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

export function getReasoningText(message: UIMessage) {
  return message.parts
    .filter(isReasoningUIPart)
    .map((part) => part.text)
    .join("\n\n");
}

export function getToolParts(message: UIMessage) {
  return message.parts.filter(isToolUIPart);
}

export function getToolName(part: ToolPart) {
  return part.type === "dynamic-tool"
    ? part.toolName
    : part.type.split("-").slice(1).join("-");
}

export function getWrittenFiles(toolParts: ToolPart[]) {
  return toolParts
    .filter(
      (part) =>
        getToolName(part) === "writeFile" && part.state === "output-available"
    )
    .map((part) => {
      if (!part.output || typeof part.output !== "object") {
        return null;
      }

      const candidate = "path" in part.output ? part.output.path : null;

      return typeof candidate === "string" ? candidate : null;
    })
    .filter((path): path is string => Boolean(path));
}

import {
  type DynamicToolUIPart,
  isToolUIPart,
  type ToolUIPart,
  type UIMessage,
} from "ai";

export interface SandboxPreviewOutput {
  directory: string | null;
  entryPath: string | null;
  port: number | null;
  url: string;
}

export interface SandboxPreviewStatus {
  errorCode: string | null;
  message: string | null;
  ok: boolean;
  status: number | null;
  statusText: string | null;
}

type PreviewToolPart = ToolUIPart | DynamicToolUIPart;

function getToolName(part: PreviewToolPart) {
  return part.type === "dynamic-tool"
    ? part.toolName
    : part.type.split("-").slice(1).join("-");
}

function readObjectField(value: unknown, field: string): string | null {
  if (!value || typeof value !== "object" || !(field in value)) {
    return null;
  }

  const candidate = value[field as keyof typeof value];

  return typeof candidate === "string" ? candidate : null;
}

function readNumberField(value: unknown, field: string): number | null {
  if (!value || typeof value !== "object" || !(field in value)) {
    return null;
  }

  const candidate = value[field as keyof typeof value];

  return typeof candidate === "number" ? candidate : null;
}

export function getPreviewOutput(
  toolParts: PreviewToolPart[]
): SandboxPreviewOutput | null {
  const previewPart = [...toolParts]
    .reverse()
    .find(
      (part) =>
        getToolName(part) === "startPreview" &&
        part.state === "output-available" &&
        readObjectField(part.output, "url")
    );

  if (!previewPart) {
    return null;
  }

  const url = readObjectField(previewPart.output, "url");

  if (!url) {
    return null;
  }

  return {
    directory: readObjectField(previewPart.output, "directory"),
    entryPath: readObjectField(previewPart.output, "entryPath"),
    port: readNumberField(previewPart.output, "port"),
    url,
  };
}

export function getLatestPreviewOutput(
  messages: UIMessage[]
): SandboxPreviewOutput | null {
  for (const message of [...messages].reverse()) {
    const preview = getPreviewOutput(message.parts.filter(isToolUIPart));

    if (preview) {
      return preview;
    }
  }

  return null;
}

export function sanitizePreviewText(text: string, previewUrl: string | null) {
  if (!(previewUrl && text.includes(previewUrl))) {
    return text;
  }

  return text.split(previewUrl).join("the Preview tab");
}

export function parsePreviewStatus(value: unknown): SandboxPreviewStatus {
  const objectValue =
    value && typeof value === "object"
      ? (value as Record<string, unknown>)
      : ({} as Record<string, unknown>);

  return {
    errorCode:
      typeof objectValue.errorCode === "string" ? objectValue.errorCode : null,
    message:
      typeof objectValue.message === "string" ? objectValue.message : null,
    ok: objectValue.ok === true,
    status: typeof objectValue.status === "number" ? objectValue.status : null,
    statusText:
      typeof objectValue.statusText === "string"
        ? objectValue.statusText
        : null,
  };
}

export function formatPreviewStatusSummary(status: SandboxPreviewStatus) {
  if (status.ok) {
    return "Preview is reachable.";
  }

  const parts = ["Preview is unavailable."];

  if (typeof status.status === "number") {
    parts.push(`HTTP ${status.status}`);
  }

  if (status.errorCode) {
    parts.push(status.errorCode);
  }

  if (status.message) {
    parts.push(status.message);
  }

  return parts.join(" ");
}

export function appendPreviewHistory(
  history: string[],
  currentIndex: number,
  url: string
) {
  const currentUrl = currentIndex >= 0 ? history[currentIndex] : null;

  if (currentUrl === url) {
    return {
      history,
      index: currentIndex,
    };
  }

  const nextHistory = history.slice(0, currentIndex + 1);
  nextHistory.push(url);

  return {
    history: nextHistory,
    index: nextHistory.length - 1,
  };
}

export function movePreviewHistory(
  history: string[],
  currentIndex: number,
  direction: -1 | 1
) {
  const nextIndex = currentIndex + direction;

  if (nextIndex < 0 || nextIndex >= history.length) {
    return null;
  }

  const nextUrl = history[nextIndex];

  if (!nextUrl) {
    return null;
  }

  return {
    index: nextIndex,
    url: nextUrl,
  };
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import { useState } from "react";

export function useSandboxAgentChat() {
  const [chat] = useState(
    () =>
      new Chat({
        transport: new DefaultChatTransport({
          api: "/api/demos/sandbox-agent",
        }),
      })
  );
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    chat,
    hasMessages,
    isBusy,
  };
}

"use client";

import { useEffect, useMemo, useState } from "react";

import { getLatestPreviewOutput } from "./preview-state";
import { samplePrompts } from "./sandbox-agent-model";
import { useSandboxAgentChat } from "./use-sandbox-agent-chat";
import { useSandboxPreviewState } from "./use-sandbox-preview-state";

export type SandboxAgentTab = "conversation" | "preview";

export function useSandboxAgentWorkspaceViewModel() {
  const [activeTab, setActiveTab] = useState<SandboxAgentTab>("conversation");
  const [isTabsMounted, setIsTabsMounted] = useState(false);
  const {
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useSandboxAgentChat();
  const latestPreview = useMemo(
    () => getLatestPreviewOutput(messages),
    [messages]
  );
  const previewState = useSandboxPreviewState(latestPreview);

  useEffect(() => {
    setIsTabsMounted(true);
  }, []);

  return {
    activeTab,
    error,
    hasMessages,
    isBusy,
    latestPreview,
    messages,
    previewState,
    samplePrompts,
    setActiveTab,
    status,
    stop,
    isTabsMounted,
    actions: {
      onOpenPreview: () => setActiveTab("preview"),
      onRegenerate: () => regenerate(),
      onSendMessage: (text: string) => sendMessage({ text }),
      onStop: stop,
      onTabChange: (value: SandboxAgentTab) => setActiveTab(value),
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import {
  appendPreviewHistory,
  formatPreviewStatusSummary,
  movePreviewHistory,
  parsePreviewStatus,
  type SandboxPreviewStatus,
} from "./preview-state";

interface PreviewLog {
  level: "error" | "log" | "warn";
  message: string;
  timestamp: Date;
}

interface LatestPreview {
  directory: string | null;
  entryPath: string | null;
  port: number | null;
  url: string;
}

export interface SandboxPreviewState {
  activePreviewUrl: string;
  appendPreviewLog: (level: PreviewLog["level"], message: string) => void;
  canGoBack: boolean;
  canGoForward: boolean;
  handleCopy: () => Promise<void>;
  handleGoBack: () => void;
  handleGoForward: () => void;
  handleOpenInNewTab: () => void;
  handlePreviewUrlChange: (nextUrl: string) => void;
  handleReload: () => void;
  handleToggleFullscreen: () => Promise<void>;
  isPreviewFullscreen: boolean;
  previewContainerRef: React.RefObject<HTMLDivElement | null>;
  previewLogs: PreviewLog[];
  previewReloadKey: number;
}

export interface PreviewHealthState {
  details: SandboxPreviewStatus | null;
  state: "checking" | "error" | "idle" | "ok";
}

export function useSandboxPreviewState(
  latestPreview: LatestPreview | null
): SandboxPreviewState {
  const [isPreviewFullscreen, setIsPreviewFullscreen] = useState(false);
  const [previewHistoryState, setPreviewHistoryState] = useState<{
    history: string[];
    index: number;
  }>({
    history: [],
    index: -1,
  });
  const [previewLogs, setPreviewLogs] = useState<PreviewLog[]>([]);
  const [previewReloadKey, setPreviewReloadKey] = useState(0);
  const [previewUrl, setPreviewUrl] = useState("");
  const previewContainerRef = useRef<HTMLDivElement | null>(null);
  const lastPreviewUrlRef = useRef<string | null>(null);
  const activePreviewUrl = previewUrl || latestPreview?.url || "";
  const canGoBack = previewHistoryState.index > 0;
  const canGoForward =
    previewHistoryState.index >= 0 &&
    previewHistoryState.index < previewHistoryState.history.length - 1;

  const appendPreviewLog = useCallback(
    (level: PreviewLog["level"], message: string) => {
      setPreviewLogs((current) => [
        ...current.slice(-49),
        {
          level,
          message,
          timestamp: new Date(),
        },
      ]);
    },
    []
  );

  const handlePreviewUrlChange = useCallback(
    (nextUrl: string) => {
      setPreviewUrl(nextUrl);
      setPreviewHistoryState((current) =>
        appendPreviewHistory(current.history, current.index, nextUrl)
      );
      appendPreviewLog("log", `Navigated to ${nextUrl}`);
    },
    [appendPreviewLog]
  );

  const handleGoBack = useCallback(() => {
    setPreviewHistoryState((current) => {
      const previous = movePreviewHistory(current.history, current.index, -1);

      if (!previous) {
        return current;
      }

      setPreviewUrl(previous.url);
      appendPreviewLog("log", `Went back to ${previous.url}`);

      return {
        history: current.history,
        index: previous.index,
      };
    });
  }, [appendPreviewLog]);

  const handleGoForward = useCallback(() => {
    setPreviewHistoryState((current) => {
      const next = movePreviewHistory(current.history, current.index, 1);

      if (!next) {
        return current;
      }

      setPreviewUrl(next.url);
      appendPreviewLog("log", `Went forward to ${next.url}`);

      return {
        history: current.history,
        index: next.index,
      };
    });
  }, [appendPreviewLog]);

  const handleReload = useCallback(() => {
    setPreviewReloadKey((current) => current + 1);

    if (activePreviewUrl) {
      appendPreviewLog("log", `Reloaded ${activePreviewUrl}`);
    }
  }, [activePreviewUrl, appendPreviewLog]);

  const handleCopy = useCallback(async () => {
    if (!activePreviewUrl) {
      appendPreviewLog("warn", "No preview URL is available yet.");
      return;
    }

    if (!navigator.clipboard) {
      appendPreviewLog("error", "Clipboard API is not available.");
      return;
    }

    try {
      await navigator.clipboard.writeText(activePreviewUrl);
      appendPreviewLog("log", `Copied ${activePreviewUrl} to the clipboard.`);
    } catch (error) {
      appendPreviewLog(
        "error",
        error instanceof Error
          ? `Failed to copy preview URL: ${error.message}`
          : "Failed to copy preview URL."
      );
    }
  }, [activePreviewUrl, appendPreviewLog]);

  const handleOpenInNewTab = useCallback(() => {
    if (!activePreviewUrl) {
      appendPreviewLog("warn", "No preview URL is available yet.");
      return;
    }

    window.open(activePreviewUrl, "_blank", "noopener,noreferrer");
    appendPreviewLog("log", `Opened ${activePreviewUrl} in a new tab.`);
  }, [activePreviewUrl, appendPreviewLog]);

  const handleToggleFullscreen = useCallback(async () => {
    const container = previewContainerRef.current;

    if (!container) {
      appendPreviewLog("warn", "Preview container is not available.");
      return;
    }

    if (document.fullscreenElement === container) {
      await document.exitFullscreen();
      appendPreviewLog("log", "Exited preview fullscreen.");
      return;
    }

    await container.requestFullscreen();
    appendPreviewLog("log", "Entered preview fullscreen.");
  }, [appendPreviewLog]);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsPreviewFullscreen(
        document.fullscreenElement === previewContainerRef.current
      );
    };

    document.addEventListener("fullscreenchange", handleFullscreenChange);

    return () => {
      document.removeEventListener("fullscreenchange", handleFullscreenChange);
    };
  }, []);

  useEffect(() => {
    const nextUrl = latestPreview?.url ?? null;

    if (!nextUrl || lastPreviewUrlRef.current === nextUrl) {
      return;
    }

    lastPreviewUrlRef.current = nextUrl;
    setPreviewUrl(nextUrl);
    setPreviewHistoryState((current) =>
      appendPreviewHistory(current.history, current.index, nextUrl)
    );
    appendPreviewLog("log", `Preview ready at ${nextUrl}`);
  }, [appendPreviewLog, latestPreview?.url]);

  return {
    activePreviewUrl,
    appendPreviewLog,
    canGoBack,
    canGoForward,
    handleCopy,
    handleGoBack,
    handleGoForward,
    handleOpenInNewTab,
    handlePreviewUrlChange,
    handleReload,
    handleToggleFullscreen,
    isPreviewFullscreen,
    previewContainerRef,
    previewLogs,
    previewReloadKey,
  };
}

export function usePreviewHealth(
  previewUrl: string,
  previewReloadKey: number,
  appendPreviewLog: SandboxPreviewState["appendPreviewLog"]
) {
  const [health, setHealth] = useState<PreviewHealthState>({
    details: null,
    state: "idle",
  });

  useEffect(() => {
    if (!previewUrl) {
      setHealth({
        details: null,
        state: "idle",
      });
      return;
    }

    let isCancelled = false;
    const controller = new AbortController();

    setHealth((current) => ({
      details: current.details,
      state: "checking",
    }));

    fetch(
      `/api/demos/sandbox-agent/preview-status?url=${encodeURIComponent(
        previewUrl
      )}&reload=${previewReloadKey}`,
      {
        cache: "no-store",
        signal: controller.signal,
      }
    )
      .then(async (response) => {
        const payload = parsePreviewStatus(await response.json());

        if (isCancelled) {
          return;
        }

        setHealth({
          details: payload,
          state: payload.ok ? "ok" : "error",
        });

        if (payload.ok) {
          appendPreviewLog("log", `Preview check succeeded for ${previewUrl}`);
          return;
        }

        appendPreviewLog("error", formatPreviewStatusSummary(payload));
      })
      .catch((error) => {
        if (isCancelled || controller.signal.aborted) {
          return;
        }

        const details = parsePreviewStatus({
          errorCode: "FETCH_FAILED",
          message:
            error instanceof Error
              ? error.message
              : "Failed to check preview URL.",
          ok: false,
          status: null,
          statusText: null,
        });

        setHealth({
          details,
          state: "error",
        });
        appendPreviewLog("error", formatPreviewStatusSummary(details));
      });

    return () => {
      isCancelled = true;
      controller.abort();
    };
  }, [appendPreviewLog, previewReloadKey, previewUrl]);

  return health;
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import {
  createAgentUIStreamResponse,
  stepCountIs,
  ToolLoopAgent,
  type UIMessage,
} from "ai";

import {
  resolveSandboxAgentChatModel,
  SANDBOX_AGENT_PROVIDER_OPTIONS,
} from "./model";
import { createSandboxAgentGateway, getSandboxAgentEnv } from "./env";
import { createSandboxAgentWorkspace } from "./workspace";

export const sandboxAgentInstructions = [
  "You are the sandbox-agent demo for a product and engineering team.",
  "Work like a focused frontend prototyper inside the sandbox workspace.",
  "Prefer plain HTML, CSS, and JavaScript unless the user asks for something heavier.",
  "Use writeFile and readFile for direct file editing, and use bash for scaffold, inspection, and iterative code changes.",
  "After the prototype is previewable, call startPreview so the workspace can show the live result.",
  "Keep the final answer concise and report the main files created or updated.",
].join(" ");

export async function streamSandboxAgent(
  messages: UIMessage[],
  {
    env = getSandboxAgentEnv(),
    localPreviewBaseUrl,
    sessionId,
    previewPort,
  }: {
    env?: ReturnType<typeof getSandboxAgentEnv>;
    localPreviewBaseUrl?: string;
    previewPort?: number;
    sessionId: string;
  }
) {
  const gateway = createSandboxAgentGateway(env);
  const chatModel = resolveSandboxAgentChatModel(env);
  const workspace = await createSandboxAgentWorkspace({
    env,
    localPreviewBaseUrl,
    sessionId,
  });
  const agent = new ToolLoopAgent({
    instructions: sandboxAgentInstructions,
    model: gateway(chatModel),
    prepareCall: ({ ...call }) => ({
      ...call,
      instructions: [
        sandboxAgentInstructions,
        `Sandbox project root: ${workspace.projectRoot}`,
        `Default artifacts root: ${workspace.artifactsRoot}`,
        `Preview port: ${previewPort ?? workspace.previewPort}`,
        `Suggested use cases:\n${workspace.suggestedUseCasesText}`,
      ].join("\n\n"),
    }),
    providerOptions: SANDBOX_AGENT_PROVIDER_OPTIONS,
    stopWhen: stepCountIs(8),
    tools: workspace.toolset.tools,
  });

  return await createAgentUIStreamResponse({
    agent,
    sendReasoning: true,
    uiMessages: messages,
  });
}

import { createGateway } from "ai";

export const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
export const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

export type AiGatewayEnvRecord = Record<string, string | undefined>;

export interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export interface AiGatewayContractConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
}

export interface AiGatewayResolvedEnv {
  apiKey: string | undefined;
  baseURL: string;
  chatModel: string;
}

export interface AiGatewaySetupConfig {
  baseURL: string;
  chatModel: string;
}

export interface AiGatewayContractSetupState<
  TConfig extends AiGatewaySetupConfig = AiGatewaySetupConfig,
> {
  config: TConfig;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

export interface AiGatewayContractOptions<
  TConfig extends AiGatewaySetupConfig = AiGatewaySetupConfig,
> {
  buildConfig?: (
    resolvedEnv: AiGatewayResolvedEnv,
    env: AiGatewayEnvRecord
  ) => TConfig;
  defaultBaseURL?: string;
  defaultChatModel: string;
  getAdditionalIssues?: (
    resolvedEnv: AiGatewayResolvedEnv,
    env: AiGatewayEnvRecord
  ) => string[];
  missingApiKeyError: string;
  missingApiKeyIssue?: string;
}

const genericMissingApiKeyIssue =
  "AI_GATEWAY_API_KEY is missing. The demo can render, but chat requests will fail until it is configured.";

export function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

export function getNodeMajor(version: string): number {
  return parseNodeVersion(version).major;
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
): number {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

export function assertSupportedNodeRuntime(version = process.version): number {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }

  return parsedVersion.major;
}

export function resolveAiGatewayContractEnv(
  env: AiGatewayEnvRecord,
  options: Pick<AiGatewayContractOptions, "defaultBaseURL" | "defaultChatModel">
): AiGatewayResolvedEnv {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL:
      env.AI_GATEWAY_BASE_URL ||
      options.defaultBaseURL ||
      DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || options.defaultChatModel,
  };
}

export function readAiGatewayContractConfig(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions
): AiGatewayContractConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveAiGatewayContractEnv(env, options);

  if (!resolvedEnv.apiKey) {
    throw new Error(options.missingApiKeyError);
  }

  return {
    apiKey: resolvedEnv.apiKey,
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function buildAiGatewayContractSetupState<
  TConfig extends AiGatewaySetupConfig,
>(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions<TConfig>
): AiGatewayContractSetupState<TConfig> {
  const issues: string[] = [];
  const resolvedEnv = resolveAiGatewayContractEnv(env, options);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(options.missingApiKeyIssue || genericMissingApiKeyIssue);
  }

  issues.push(...(options.getAdditionalIssues?.(resolvedEnv, env) ?? []));

  return {
    config:
      options.buildConfig?.(resolvedEnv, env) ??
      ({
        baseURL: resolvedEnv.baseURL,
        chatModel: resolvedEnv.chatModel,
      } as TConfig),
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function createAiGatewayFromContract(
  env: AiGatewayEnvRecord,
  options: AiGatewayContractOptions
): ReturnType<typeof createGateway> {
  const { apiKey, baseURL } = readAiGatewayContractConfig(env, options);

  return createGateway({
    apiKey,
    baseURL,
  });
}

