  readonly sessionId: string;
  startPreview(options?: {
    directory?: string;
    entryPath?: string;
    port?: number;
  }): Promise<SandboxAgentPreview>;
  stop(): Promise<void>;
  writeFile(
    targetPath: string,
    content: string
  ): Promise<{
    bytes: number;
    path: string;
  }>;
}

export interface SandboxAgentSessionRegistry {
  getDomain(sessionId: string, port: number): string;
  getSession(sessionId: string): SandboxAgentSession;
  stopSession(sessionId: string): Promise<void>;
}

interface SandboxAgentSessionRegistryOptions {
  localPreviewBaseUrl?: string;
}

function quoteShell(value: string) {
  return `'${value.replace(/'/g, `'"'"'`)}'`;
}

function normalizeEntryPath(entryPath: string) {
  return entryPath.startsWith("/") ? entryPath : `/${entryPath}`;
}

function sleep(ms: number) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function buildPreviewLaunchScript({
  directory,
  port,
}: {
  directory: string;
  port: number;
}) {
  return `exec node ${quoteShell(SANDBOX_AGENT_PREVIEW_SERVER_PATH)} --root ${quoteShell(directory)} --port ${port} >/tmp/sandbox-agent-preview.log 2>&1`;
}

async function readPreviewLog(
  session: Pick<SandboxAgentSession, "runCommand">
) {
  const logResult = await session.runCommand(
    "cat /tmp/sandbox-agent-preview.log 2>/dev/null || true"
  );

  return logResult.stdout.trim();
}

export async function waitForSandboxPreview({
  entryPath,
  fetchPreview = globalThis.fetch,
  retries = 12,
  retryDelayMs = 1000,
  session,
  url,
}: {
  entryPath: string;
  fetchPreview?: typeof globalThis.fetch;
  retries?: number;
  retryDelayMs?: number;
  session: Pick<SandboxAgentSession, "runCommand">;
  url: string;
}) {
  let lastError = "";

  for (let attempt = 0; attempt < retries; attempt += 1) {
    try {
      const response = await fetchPreview(url, {
        cache: "no-store",
      });

      if (response.ok) {
        return;
      }

      const responseBody = await response.text().catch(() => "");
      lastError = [
        `HTTP ${response.status} ${response.statusText}`,
        responseBody.trim(),
      ]
        .filter(Boolean)
        .join(" ");
    } catch (error) {
      lastError =
        error instanceof Error ? error.message : "Unknown preview fetch error";
    }

    if (attempt < retries - 1) {
      await sleep(retryDelayMs);
    }
  }

  const previewLog = await readPreviewLog(session);
  const details = [
    `Preview URL did not become reachable for "${entryPath}".`,
    lastError ? `Last probe error: ${lastError}` : null,
    previewLog ? `Preview log: ${previewLog}` : null,
  ]
    .filter(Boolean)
    .join(" ");

  throw new Error(details);
}

export async function launchDetachedSandboxPreview({
  directory,
  port,
  sandbox,
  session,
}: {
  directory: string;
  port: number;
  sandbox: DetachedPreviewSandboxHandle;
  session: Pick<SandboxAgentSession, "runCommand">;
}) {
  await session.runCommand(
    `pkill -f ${quoteShell(SANDBOX_AGENT_PREVIEW_SERVER_PATH)} >/dev/null 2>&1 || true`
  );

  await sandbox.runCommand({
    args: ["-lc", buildPreviewLaunchScript({ directory, port })],
    cmd: "bash",
    cwd: SANDBOX_PROJECT_ROOT,
    detached: true,
  });
}

async function createVercelBackedSandboxAgentSessionRegistry(
  env: SandboxAgentEnv
): Promise<SandboxAgentSessionRegistry> {
  const {
    createVercelSandbox,
    createVercelSandboxSessionRegistry,
    VERCEL_SANDBOX_WORKSPACE_ROOT,
  } = await import("./vercel-sandbox");
  const sandboxHandles = new Map<string, NamedSandboxHandle>();
  const baseRegistry: BaseSandboxSessionRegistry =
    createVercelSandboxSessionRegistry({
      createSandbox: async (sessionId) => {
        const sandbox = await createVercelSandbox(sessionId, env, {
          ports: [SANDBOX_AGENT_PREVIEW_PORT],
        });
        sandboxHandles.set(
          sessionId,
          sandbox as unknown as NamedSandboxHandle
        );
        return sandbox;
      },
      workspaceRoot: VERCEL_SANDBOX_WORKSPACE_ROOT,
    });

  const registry: SandboxAgentSessionRegistry = {
    getDomain(sessionId, port) {
      const sandbox = sandboxHandles.get(sessionId);

      if (!sandbox) {
        throw new Error(
          `Sandbox handle for session "${sessionId}" is not available yet.`
        );
      }

      return sandbox.domain(port);
    },
    getSession(sessionId) {
      const baseSession = baseRegistry.getSession(sessionId);

      return {
        artifactsRoot: SANDBOX_ARTIFACTS_ROOT,
        projectRoot: SANDBOX_PROJECT_ROOT,
        pathExists: (targetPath) => baseSession.pathExists(targetPath),
        readFile: (targetPath) => baseSession.readFile(targetPath),
        runCommand: (command) => baseSession.runCommand(command),
        sessionId,
        async startPreview({
          directory = ".",
          entryPath = "/index.html",
          port = SANDBOX_AGENT_PREVIEW_PORT,
        } = {}) {
          const directoryExists = await baseSession.pathExists(directory);

          if (!directoryExists) {
            throw new Error(
              `Preview directory "${directory}" does not exist in the sandbox workspace.`
            );
          }

          await baseSession.writeFile(
            SANDBOX_AGENT_PREVIEW_SERVER_PATH,
            SANDBOX_AGENT_PREVIEW_SERVER_SOURCE
          );
          const sandbox = sandboxHandles.get(sessionId);

          if (!sandbox) {
            throw new Error(
              `Sandbox handle for session "${sessionId}" is not available when starting the preview server.`
            );
          }

          await launchDetachedSandboxPreview({
            directory,
            port,
            sandbox: sandbox as DetachedPreviewSandboxHandle,
            session: baseSession,
          });

          const preview = {
            directory,
            entryPath: normalizeEntryPath(entryPath),
            port,
            url: `${registry.getDomain(sessionId, port)}${normalizeEntryPath(entryPath)}`,
          };

          await waitForSandboxPreview({
            entryPath: preview.entryPath,
            session: baseSession,
            url: preview.url,
          });

          return preview;
        },
        stop: () => baseSession.stop(),
        writeFile: (targetPath, content) =>
          baseSession.writeFile(targetPath, content),
      };
    },
    stopSession(sessionId) {
      return baseRegistry.stopSession(sessionId);
    },
  };

  return registry;
}

export async function createSandboxAgentSessionRegistry(
  env: SandboxAgentEnv = getSandboxAgentEnv(),
  options: SandboxAgentSessionRegistryOptions = {}
): Promise<SandboxAgentSessionRegistry> {
  const setupState = getSandboxAgentSandboxSetupState(env);

  if (setupState.authMode === "local") {
    const { createLocalSandboxAgentSessionRegistry } =
      await import("./local-sandbox");

    return createLocalSandboxAgentSessionRegistry({
      localPreviewBaseUrl: options.localPreviewBaseUrl,
      previewPort: SANDBOX_AGENT_PREVIEW_PORT,
    });
  }

  return createVercelBackedSandboxAgentSessionRegistry(env);
}

let sharedRegistry: SandboxAgentSessionRegistry | null = null;
let sharedRegistryMode:
  | ReturnType<typeof getSandboxAgentSandboxSetupState>["authMode"]
  | null = null;
let sharedLocalPreviewBaseUrl: string | undefined;

export async function getSharedSandboxAgentSessionRegistry(
  env: SandboxAgentEnv = getSandboxAgentEnv(),
  options: SandboxAgentSessionRegistryOptions = {}
) {
  const setupState = getSandboxAgentSandboxSetupState(env);

  if (options.localPreviewBaseUrl) {
    sharedLocalPreviewBaseUrl = options.localPreviewBaseUrl;
  }

  if (!sharedRegistry || sharedRegistryMode !== setupState.authMode) {
    sharedRegistry = await createSandboxAgentSessionRegistry(env, {
      localPreviewBaseUrl: sharedLocalPreviewBaseUrl,
    });
    sharedRegistryMode = setupState.authMode;
  }

  return sharedRegistry;
}

import { readdir, readFile, stat } from "node:fs/promises";
import path, { posix as posixPath } from "node:path";
import { Sandbox } from "@vercel/sandbox";
import {
  getSandboxAgentEnv,
  getSandboxAgentSandboxSetupState,
  getSandboxAgentSandboxTokenCredentials,
  type SandboxAgentEnv,
} from "./env";

export const VERCEL_SANDBOX_WORKSPACE_ROOT = process.cwd();
export const VERCEL_SANDBOX_PROJECT_ROOT = "/vercel/sandbox/project";
export const VERCEL_SANDBOX_SKILLS_ROOT =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/.agents/skills`;
export const VERCEL_SANDBOX_ARTIFACTS_ROOT =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/artifacts`;
export const VERCEL_SANDBOX_AGENTS_FILE =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/AGENTS.md`;

interface SandboxFs {
  exists(path: string): Promise<boolean>;
  mkdir(path: string, options?: { recursive?: boolean }): Promise<void>;
  readFile(path: string, encoding: BufferEncoding | "utf-8"): Promise<string>;
  writeFile(
    path: string,
    content: string | Uint8Array,
    encoding?: BufferEncoding | "utf-8"
  ): Promise<void>;
}

export interface VercelSandboxHandle {
  fs: SandboxFs;
  runCommand(options: { args: string[]; cmd: string; cwd: string }): Promise<{
    exitCode: number;
    stderr(): Promise<string>;
    stdout(): Promise<string>;
  }>;
  stop(): Promise<unknown>;
}

export type VercelSandboxFactory = (
  sessionId: string
) => Promise<VercelSandboxHandle>;

export interface VercelSandboxSession {
  readonly artifactsRoot: string;
  pathExists(targetPath: string): Promise<boolean>;
  readonly projectRoot: string;
  readFile(targetPath: string): Promise<string>;
  runCommand(command: string): Promise<{
    command: string;
    exitCode: number;
    stderr: string;
    stdout: string;
  }>;
  readonly sessionId: string;
  stop(): Promise<void>;
  writeFile(
    targetPath: string,
    content: string
  ): Promise<{
    bytes: number;
    path: string;
  }>;
}

export interface VercelSandboxSessionRegistry {
  getSandbox(sessionId: string): Promise<VercelSandboxHandle>;
  getSession(sessionId: string): VercelSandboxSession;
  stopSession(sessionId: string): Promise<void>;
}

interface SessionEntry {
  sandboxPromise: Promise<VercelSandboxHandle> | null;
  seededBaseWorkspace: boolean;
}

export async function createVercelSandbox(
  sessionId: string,
  env: SandboxAgentEnv = getSandboxAgentEnv(),
  options: {
    ports?: number[];
  } = {}
): Promise<VercelSandboxHandle> {
  const setupState = getSandboxAgentSandboxSetupState(env);

  if (!setupState.isReady) {
    throw new Error(setupState.issues.join(" "));
  }

  const baseOptions = {
    name: sessionId,
    persistent: true,
    ports: options.ports,
    runtime: setupState.runtime,
    timeout: 300_000,
  };

  if (setupState.authMode === "oidc") {
    try {
      return (await Sandbox.get({
        name: sessionId,
      })) as unknown as VercelSandboxHandle;
    } catch {
      return (await Sandbox.create(
        baseOptions
      )) as unknown as VercelSandboxHandle;
    }
  }

  const tokenCredentials = getSandboxAgentSandboxTokenCredentials(env);

  try {
    return (await Sandbox.get({
      name: sessionId,
      projectId: tokenCredentials.projectId,
      teamId: tokenCredentials.teamId,
      token: tokenCredentials.token,
    })) as unknown as VercelSandboxHandle;
  } catch {
    return (await Sandbox.create({
      ...baseOptions,
      projectId: tokenCredentials.projectId,
      teamId: tokenCredentials.teamId,
      token: tokenCredentials.token,
    })) as unknown as VercelSandboxHandle;
  }
}

async function pathExists(localPath: string) {
  try {
    await stat(localPath);
    return true;
  } catch (error) {
    if (
      typeof error === "object" &&
      error !== null &&
      "code" in error &&
      error.code === "ENOENT"
    ) {
      return false;
    }

    throw error;
  }
}

export async function copyLocalPathToSandbox(
  sandbox: VercelSandboxHandle,
  localPath: string,
  remotePath: string
) {
  const entry = await stat(localPath);

  if (entry.isDirectory()) {
    await sandbox.fs.mkdir(remotePath, { recursive: true });

    for (const child of await readdir(localPath)) {
      await copyLocalPathToSandbox(
        sandbox,
        path.join(localPath, child),
        posixPath.join(remotePath, child)
      );
    }

    return;
  }

  await sandbox.fs.mkdir(posixPath.dirname(remotePath), { recursive: true });
  await sandbox.fs.writeFile(remotePath, await readFile(localPath));
}

function resolveSandboxPath(targetPath: string) {
  if (targetPath.startsWith("/")) {
    return targetPath;
  }

  return posixPath.join(VERCEL_SANDBOX_PROJECT_ROOT, targetPath);
}

function shellQuote(value: string) {
  return `'${value.replace(/'/g, `'"'"'`)}'`;
}

function formatSandboxError(error: unknown) {
  if (!(error instanceof Error)) {
    return String(error);
  }

  const details = [
    "response" in error &&
    typeof error.response === "object" &&
    error.response &&
    "status" in error.response &&
    typeof error.response.status === "number"
      ? `HTTP ${error.response.status}`
      : null,
    "sandboxName" in error && typeof error.sandboxName === "string"
      ? `sandbox=${error.sandboxName}`
      : null,
    "sessionId" in error && typeof error.sessionId === "string"
      ? `session=${error.sessionId}`
      : null,
    "json" in error && typeof error.json === "object" && error.json
      ? `json=${JSON.stringify(error.json)}`
      : null,
    "text" in error && typeof error.text === "string" && error.text
      ? `text=${error.text}`
      : null,
    error.message ? `message=${error.message}` : null,
  ].filter(Boolean);

  return details.join(" | ") || error.message;
}

function createSandboxOperationError({
  action,
  error,
  target,
}: {
  action: string;
  error: unknown;
  target: string;
}) {
  return new Error(
    `Sandbox ${action} failed for ${target}. ${formatSandboxError(error)}`
  );
}

async function writeSandboxFile(
  sandbox: VercelSandboxHandle,
  resolvedPath: string,
  content: string
) {
  try {
    await sandbox.fs.mkdir(posixPath.dirname(resolvedPath), {
      recursive: true,
    });
    await sandbox.fs.writeFile(resolvedPath, content, "utf-8");
    return;
  } catch (primaryError) {
    const base64Content = Buffer.from(content, "utf-8").toString("base64");
    const fallbackCommand = [
      `mkdir -p ${shellQuote(posixPath.dirname(resolvedPath))}`,
      `base64 -d > ${shellQuote(resolvedPath)} <<'__SKILLS_AGENT_CONTENT__'`,
      base64Content,
      "__SKILLS_AGENT_CONTENT__",
    ].join("\n");

    let fallbackResult: Awaited<ReturnType<VercelSandboxHandle["runCommand"]>>;

    try {
      fallbackResult = await sandbox.runCommand({
        args: ["-lc", fallbackCommand],
        cmd: "bash",
        cwd: VERCEL_SANDBOX_PROJECT_ROOT,
      });
    } catch (fallbackError) {
      throw new Error(
        [
          `Sandbox writeFile failed for ${resolvedPath}.`,
          `File API error: ${formatSandboxError(primaryError)}`,
          `Shell fallback error: ${formatSandboxError(fallbackError)}`,
        ].join(" ")
      );
    }

    if (fallbackResult.exitCode === 0) {
      return;
    }

    throw new Error(
      [
        "Failed to write a sandbox file.",
        `File API error: ${formatSandboxError(primaryError)}`,
        `Shell fallback error: ${(await fallbackResult.stderr()).trim() || "unknown error"}`,
      ].join(" ")
    );
  }
}

export function createVercelSandboxSessionRegistry({
  createSandbox,
  workspaceRoot = VERCEL_SANDBOX_WORKSPACE_ROOT,
}: {
  createSandbox: VercelSandboxFactory;
  workspaceRoot?: string;
}): VercelSandboxSessionRegistry {
  const entries = new Map<string, SessionEntry>();

  const stopSession = async (sessionId: string) => {
    const entry = entries.get(sessionId);

    if (!entry) {
      return;
    }

    if (!entry.sandboxPromise) {
      entries.delete(sessionId);
      return;
    }

    let sandbox: VercelSandboxHandle;

    try {
      sandbox = await entry.sandboxPromise;
    } catch {
      entries.delete(sessionId);
      return;
    }

    await sandbox.stop();
    entries.delete(sessionId);
  };

  const getOrCreateEntry = (sessionId: string) => {
    const existingEntry = entries.get(sessionId);

    if (existingEntry) {
      return existingEntry;
    }

    const createdEntry: SessionEntry = {
      sandboxPromise: null,
      seededBaseWorkspace: false,
    };
    entries.set(sessionId, createdEntry);
    return createdEntry;
  };

  const ensureSandbox = async (sessionId: string, entry: SessionEntry) => {
    if (!entry.sandboxPromise) {
      entry.sandboxPromise = (async () => {
        let lastError: unknown;

        for (let attempt = 0; attempt < 2; attempt += 1) {
          try {
            const sandbox = await createSandbox(sessionId);

            if (!entry.seededBaseWorkspace) {
              await sandbox.fs.mkdir(VERCEL_SANDBOX_PROJECT_ROOT, {
                recursive: true,
              });
              await sandbox.fs.mkdir(VERCEL_SANDBOX_SKILLS_ROOT, {
                recursive: true,
              });
              await sandbox.fs.mkdir(VERCEL_SANDBOX_ARTIFACTS_ROOT, {
                recursive: true,
              });

              const agentsPath = path.join(
                /*turbopackIgnore: true*/ workspaceRoot,
                "AGENTS.md"
              );

              if (await pathExists(agentsPath)) {
                await copyLocalPathToSandbox(
                  sandbox,
                  agentsPath,
                  VERCEL_SANDBOX_AGENTS_FILE
                );
              }

              entry.seededBaseWorkspace = true;
            }

            return sandbox;
          } catch (error) {
            lastError = error;
            entry.seededBaseWorkspace = false;
          }
        }

        throw lastError;
      })().catch((error) => {
        entry.sandboxPromise = null;
        throw error;
      });
    }

    return await entry.sandboxPromise;
  };

  return {
    getSandbox(sessionId) {
      const entry = getOrCreateEntry(sessionId);
      return ensureSandbox(sessionId, entry);
    },
    getSession(sessionId) {
      const entry = getOrCreateEntry(sessionId);

      return {
        artifactsRoot: VERCEL_SANDBOX_ARTIFACTS_ROOT,
        projectRoot: VERCEL_SANDBOX_PROJECT_ROOT,
        sessionId,
        async pathExists(targetPath) {
          const sandbox = await ensureSandbox(sessionId, entry);
          return sandbox.fs.exists(resolveSandboxPath(targetPath));
        },
        async readFile(targetPath) {
          const sandbox = await ensureSandbox(sessionId, entry);
          const resolvedPath = resolveSandboxPath(targetPath);

          try {
            return await sandbox.fs.readFile(resolvedPath, "utf-8");
          } catch (error) {
            throw createSandboxOperationError({
              action: "readFile",
              error,
              target: resolvedPath,
            });
          }
        },
        async runCommand(command) {
          const sandbox = await ensureSandbox(sessionId, entry);
          let result: Awaited<ReturnType<VercelSandboxHandle["runCommand"]>>;

          try {
            result = await sandbox.runCommand({
              args: ["-lc", command],
              cmd: "bash",
              cwd: VERCEL_SANDBOX_PROJECT_ROOT,
            });
          } catch (error) {
            throw createSandboxOperationError({
              action: "bash",
              error,
              target: command,
            });
          }

          return {
            command,
            exitCode: result.exitCode,
            stderr: await result.stderr(),
            stdout: await result.stdout(),
          };
        },
        async stop() {
          await stopSession(sessionId);
        },
        async writeFile(targetPath, content) {
          const sandbox = await ensureSandbox(sessionId, entry);
          const resolvedPath = resolveSandboxPath(targetPath);

          await writeSandboxFile(sandbox, resolvedPath, content);

          return {
            bytes: Buffer.byteLength(content, "utf-8"),
            path: resolvedPath,
          };
        },
      };
    },
    stopSession,
  };
}

let sharedRegistry: VercelSandboxSessionRegistry | null = null;

export function getSharedVercelSandboxSessionRegistry(
  env: SandboxAgentEnv = getSandboxAgentEnv()
) {
  sharedRegistry ??= createVercelSandboxSessionRegistry({
    createSandbox: (sessionId) => createVercelSandbox(sessionId, env),
  });

  return sharedRegistry;
}

import {
  createSandboxAgentToolset,
  type SandboxAgentToolset,
} from "./official-tools";
import {
  getSharedSandboxAgentSessionRegistry,
  SANDBOX_AGENT_PREVIEW_PORT,
  type SandboxAgentSession,
} from "./session";
import { getSandboxAgentEnv, type SandboxAgentEnv } from "./env";

export const defaultSandboxAgentSuggestedUseCases = [
  "Build a pricing landing page with an interactive calculator and start a live preview.",
  "Create a product microsite with HTML, CSS, and JavaScript, then expose the result through the sandbox preview.",
  "Iterate on a generated landing page, update the copy and calculator logic, and refresh the same sandbox preview.",
] as const;

export interface SandboxAgentWorkspace {
  readonly artifactsRoot: string;
  readonly previewPort: number;
  readonly projectRoot: string;
  readonly session: SandboxAgentSession;
  readonly suggestedUseCases: readonly string[];
  readonly suggestedUseCasesText: string;
  readonly toolset: SandboxAgentToolset;
}

export function formatSuggestedUseCases(useCases: readonly string[]) {
  return useCases.map((useCase) => `- ${useCase}`).join("\n");
}

export async function createSandboxAgentWorkspace(
  {
    env = getSandboxAgentEnv(),
    localPreviewBaseUrl,
    sessionId,
    suggestedUseCases = defaultSandboxAgentSuggestedUseCases,
  }: {
    env?: SandboxAgentEnv;
    localPreviewBaseUrl?: string;
    sessionId: string;
    suggestedUseCases?: readonly string[];
  },
  dependencies: {
    createToolset?: typeof createSandboxAgentToolset;
    getSession?: (sessionId: string) => SandboxAgentSession;
  } = {}
): Promise<SandboxAgentWorkspace> {
  const registry = await getSharedSandboxAgentSessionRegistry(env, {
    localPreviewBaseUrl,
  });
  const getSession =
    dependencies.getSession ?? registry.getSession.bind(registry);
  const session = getSession(sessionId);
  const createToolset = dependencies.createToolset ?? createSandboxAgentToolset;
  const toolset = await createToolset({
    projectRoot: session.projectRoot,
    session,
  });

  return {
    artifactsRoot: session.artifactsRoot,
    previewPort: SANDBOX_AGENT_PREVIEW_PORT,
    projectRoot: session.projectRoot,
    session,
    suggestedUseCases,
    suggestedUseCasesText: formatSuggestedUseCases(suggestedUseCases),
    toolset,
  };
}
